/*
 * We do NOT use typedef struct here. Writing 'struct inode *inode'
 * is better than 'inode_t *inode' because the struct keyword tells
 * you exactly what you are looking at.
 */
struct inode *lookup_inode(unsigned long ino)
{
	return iget_locked(current->nsproxy->mnt_ns->root->d_sb, ino);
}
